<template >
    <div class = "org-itm"
         :class = "isOpened ? '--opened' : ''" >
        <button class = "org-itm__top"
                @click = "toggleView"
                type = "button" >
            <span class = "org-itm-ico" data-abbr = "МТ" >
                <img :src = "org.logo" alt = "" >
            </span >
            <span class = "org-itm-name h3" >{{org.name}}</span >
            <svg class = "org-itm-ch" >
                <use xlink:href = "../assets/icons.svg#chevron" ></use >
            </svg >
        </button >
        <div v-show = "isOpened" class = "org-itm__cnt" >
            <div class = "row org-itm-bl" >
                <div class = "col-md-5 mb-2 mb-md-0" >
                    <ul class = "org-itm-fin" >
                        <li >
                            <p class = "subtext text-secondary" >Тариф</p >
                            <p class = "subtext summ" >{{org.tariff}}</p >
                        </li >
                        <li >
                            <p class = "subtext text-secondary" >Налоговая система</p >
                            <p class = "subtext summ" >{{org.tax_system}}</p >
                        </li >
                        <li >
                            <p class = "subtext text-secondary" >ИИН</p >
                            <p class = "subtext summ" >{{org.iin}}</p >
                        </li >
                        <li >
                            <p class = "subtext text-secondary" >БИН</p >
                            <p class = "subtext summ" >{{org.bin}}</p >
                        </li >
                    </ul >
                </div >
                <div class = "col-md-7" >
                    <ul class = "org-itm-lnk" >
                        <li >
                            <a href = "javascript:void(0)" class = "org-itm-lnk__itm" >
                                <svg >
                                    <use xlink:href = "../assets/icons.svg#buh" ></use >
                                </svg >
                                <span class = "caption" >1С:Бухгалтерия 8 для Казахстана</span >
                            </a >
                        </li >
                        <li >
                            <a href = "javascript:void(0)" class = "org-itm-lnk__itm" >
                                <svg >
                                    <use xlink:href = "../assets/icons.svg#unf" ></use >
                                </svg >
                                <span class = "caption" >Зарплата и управление персоналом</span >
                            </a >
                        </li >
                        <li >
                            <a href = "javascript:void(0)" class = "org-itm-lnk__itm" >
                                <svg >
                                    <use xlink:href = "../assets/icons.svg#zp" ></use >
                                </svg >
                                <span class = "caption" >Управление нашей фирмой</span >
                            </a >
                        </li >
                    </ul >
                </div >
            </div >
            <div class = "org-itm-bl" >
                <p class = "summ mb-1" >Журналы учета оказанных услуг</p >
                <div class = "row align-items-center" >
                    <div class = "col-md-7 mb-2 mb-md-0 " >
                        <p class = "subtext" >Доступен журнал за Октябрь 2020 года</p >
                    </div >
                    <div class = "col-md-5 d-flex justify-content-md-end" >
                        <p class = "title mx-md-4 " >{{org.profit}}</p >
                        <a href = "../assets/docs/sample.pdf"
                           class = "file-btn ml-auto ml-md-0"
                           download = "" >
                            <svg >
                                <use xlink:href = "../assets/icons.svg#download" ></use >
                            </svg >
                        </a >
                        <button class = "file-btn btn-reset"
                                @click = "print($event.target)"
                                data-print = "../assets/docs/sample.pdf"
                                type = "button" >
                            <svg >
                                <use xlink:href = "../assets/icons.svg#print" ></use >
                            </svg >
                        </button >
                    </div >
                </div >
            </div >
            <div class = "org-itm-bl" >
                <dl v-if = "org.contract.length"
                    class = "doc-list"
                    :class = "org.contract.length > 4 ? 'colls' : ''" >
                    <dt class = "caption summ" >Договор</dt >
                    <dd v-for = "(item, key) in org.contract" :key = "key" >
                        <a :href = "item.link" class = "subtext" download = "" >{{item.name}}</a >
                    </dd >
                </dl >
                <dl v-if = "org.log_book.length"
                    class = "doc-list"
                    :class = "org.log_book.length > 4 ? 'colls' : ''" >
                    <dt class = "caption summ" >Договор</dt >
                    <dd v-for = "(item, key) in org.log_book" :key = "key" >
                        <a :href = "item.link" class = "subtext" download = "" >{{item.name}}</a >
                    </dd >
                </dl >
            </div >
        </div >
    </div >
</template >

<script >
  import printJS from "print-js/dist/print";

  export default {
    name: "org_itm",
    props: [
      "org",
    ],
    data() {
      return {
        isOpened: false,
      };
    },
    methods: {
      toggleView: function () {
        this.isOpened = !this.isOpened;
      },
      print: function (el) {
        let link = el.closest("button")?.dataset.print;
        if (link) {
          printJS({
            printable: link,
            type: "pdf",
            showModal: false,
          });
        }
      },
    },
  };
</script >

<style scoped >
    @import "../includes/styles/_grid.css";
    @import "../includes/styles/_buttons.css";

    .org-itm {
        box-shadow: 0 0 7px rgba(0, 0, 0, 0.05);
        border-radius: 6px;
        }

    .org-itm:not(:last-child) {margin-bottom: 30px;}

    .org-itm .org-itm__top {
        position: relative;
        display: flex;
        width: 100%;
        padding: 15px 55px 15px 20px;
        flex-flow: row nowrap;
        align-items: center;
        background: #FEDD46;
        border: none;
        border-radius: 6px 6px 0 0;
        transition: all .2s linear;
        }

    .org-itm .org-itm__top:hover {
        background: #FFD516;
        }

    .org-itm .org-itm__cnt {
        padding: 15px;
        transition: all .2s linear;
        }

    .org-itm .org-itm-ico {
        display: block;
        width: 40px;
        height: 40px;
        flex-shrink: 0;
        margin-right: 18px;
        transition: all .2s linear;
        }

    .org-itm:not(.--opened) .org-itm-ico {filter: grayscale(1) brightness(60%)}

    .org-itm .org-itm-ch {
        position: absolute;
        top: calc(50% - 12px);
        right: 24px;
        display: block;
        width: 24px;
        height: 24px;
        transition: all .2s linear;
        }

    .org-itm.--opened .org-itm-ch {transform: rotateX(.5turn)}

    .org-itm-fin {
        display: grid;
        grid-template-columns: repeat(2, 1fr);
        grid-gap: 15px;
        }

    .org-itm-lnk {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
        grid-gap: 15px;
        }

    .org-itm-lnk .org-itm-lnk__itm {
        --c1: #454242;
        --c2: #B7B7B7;

        display: flex;
        padding: 12px 5px;
        flex-direction: column;
        align-items: center;
        background-color: #fff;
        border-radius: 6px;
        text-align: center;
        text-decoration: none;
        transition: all .2s linear;

        }

    .org-itm-lnk .org-itm-lnk__itm:hover {
        box-shadow: 0 4px 6px rgba(205, 205, 205, 0.3);
        --c2: #FFD516;
        }

    .org-itm-lnk .org-itm-lnk__itm svg {
        display: inline-block;
        width: 40px;
        height: 40px;
        margin-bottom: 8px;
        }

    .org-itm .org-itm-bl:not(:last-child) {
        padding-bottom: 15px;
        margin-bottom: 15px;
        border-bottom: 1px solid #ECECEC;
        }

    .file-btn {
        --c1: #8C8C8C;
        --c2: #8C8C8C;

        display: block;
        width: 30px;
        height: 30px;
        margin-left: 5px;
        margin-right: 5px;
        }

    .file-btn:hover {
        --c1: #454242;
        --c2: #FFD516;
        }

    .file-btn svg {
        display: block;
        width: 100%;
        height: 100%;
        }

    .doc-list:not(:last-child) {margin-bottom: 17px;}

    .doc-list a {
        display: inline-block;
        padding: 3px 6px;
        border-radius: 4px;
        text-decoration: none;
        transition: all .2s linear;
        break-inside: avoid;
        }

    .doc-list a:hover {
        background-color: rgba(254, 221, 70, 0.37);
        }

    .doc-list dt {
        padding: 7px 16px;
        margin-bottom: 5px;
        background: #F7F7F7;
        border-radius: 4px;
        }

    .doc-list dd {
        margin-left: 18px;
        margin-bottom: 7px;
        }

    @media (min-width: 768px) {
        .org-itm .org-itm__cnt {
            padding: 15px 25px 30px 78px;
            }
        .org-itm-fin {
            grid-gap: 25px 41px;
            }
        .doc-list.colls {
            column-count: 2;
            column-gap: 46px;
            }
        .doc-list dt {column-span: all;}
        }
</style >