<template >
    <div id = "app" >
        <div class = "organizations content" >
            <org v-for = "(item, key) in orgList"
                 :key = "key"
                 :org = "item" ></org >
        </div >
        <notes></notes>
    </div >
</template >

<script >
  import axios from "axios";
  import org from "./components/org_itm";
  import notifications from "./components/notifications";


  export default {
    name: "organizations",
    data() {
      return {
        orgList: [],
      };
    },
    components: {
      org,
      notes: notifications,
    },
    methods: {
      getOrg: function () {
        axios.get(
            "/json/organizations.json",
            {
              headers: {
                "Content-Type": "application/json",
              },
            },
        ).then(response => {
          this.orgList = response.data;
        }).catch(error => console.error(error));
      },
    },
    mounted() {
      this.getOrg();
    },
  };
</script >

<style >
    @import url('https://fonts.googleapis.com/css2?family=PT+Sans:ital,wght@0,400;0,700;1,400;1,700&display=swap');
    @import "includes/styles/_reset.css";
    @import 'includes/styles/_typo.css';
    @import 'includes/styles/_template.css';

    .organizations {
        margin-top: 20px;
        margin-bottom: 20px;
        }

</style >
